// frontend/src/hooks/useSensor.js
import { useBluetoothSensor } from './useBluetoothSensor';

export const useSensor = () => {
    const {
        status,
        loading,
        error,
        connect,
        disconnect,
        scanFingerprint,
        enrollFingerprint,
        isBluetoothSupported
    } = useBluetoothSensor();
    
    return {
        status: {
            connected: status.connected,
            port: status.device?.name || 'Bluetooth'
        },
        loading,
        error,
        connect,
        disconnect,
        scanFingerprint,
        enrollFingerprint,
        isBluetoothSupported
    };
};
